fun solve(weight: Array<Long>): Long {
    val n = weight.size
    var count = 0L
    var start = 0
    var i = 1
    var currMax = weight[0]
    while (i < n) {
        if (start == i) {
            currMax = weight[i]
            i++
        } else {
            if (weight[i] < currMax) {
                count++
                start = i + 1
                if (start < n) {
                    i = start
                } else {
                    break
                }
            } else {
                currMax = maxOf(currMax, weight[i])
